import{_ as i,o as l,c as e,a3 as o}from"./chunks/framework.BlfGB29P.js";const g=JSON.parse('{"title":"功能清单","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/basic-app/features.md","filePath":"cosmos/basic-app/features.md","lastUpdated":1783773945000}'),r={name:"cosmos/basic-app/features.md"};function t(s,a,n,c,d,h){return l(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="功能清单" tabindex="-1">功能清单 <a class="header-anchor" href="#功能清单" aria-label="Permalink to &quot;功能清单&quot;">​</a></h1><p>XiHan.BasicApp 内置了中后台系统所需的完整能力。以下按领域列出。</p><h2 id="身份与认证" tabindex="-1">身份与认证 <a class="header-anchor" href="#身份与认证" aria-label="Permalink to &quot;身份与认证&quot;">​</a></h2><ul><li>用户、角色、部门、菜单管理</li><li><strong>JWT 双令牌</strong>（Access + Refresh），多端登录与会话管理</li><li>多种登录方式：账号密码、邮箱 / 短信验证码、OAuth2（GitHub / Gitee / Google / QQ）、2FA（TOTP / 邮箱 / 短信）</li><li>密码 PBKDF2 哈希；一次性验证码消费即销毁、恒定时间比较</li></ul><h2 id="权限-rbac-abac" tabindex="-1">权限（RBAC + ABAC） <a class="header-anchor" href="#权限-rbac-abac" aria-label="Permalink to &quot;权限（RBAC + ABAC）&quot;">​</a></h2><ul><li>权限码 <code>module:resource:action</code>（如 <code>saas:user:read</code>），超级管理员用字面通配 <code>*</code></li><li>角色层级继承（闭包表）、数据范围（本人 / 部门 / 租户，独立于权限码的维度）、字段级脱敏</li><li>ABAC 属性条件（挂在角色权限 / 用户直授权限上，同组 AND、组间 OR）：时间窗、IP、资源状态、数值阈值等 <code>subject.</code> / <code>resource.</code> / <code>environment.</code> 命名空间表达式</li><li><strong>约束规则引擎</strong>：静态 / 动态职责分离（SSD / DSD）、互斥、基数、先决条件、时间、位置（IP）、自定义共 8 类，违规可拒绝 / 警告 / 仅记录 / 转审批</li><li>权限委托（委托人 → 被委托人 → 权限或角色范围 → 生效 / 到期时间窗，可随时撤销）</li><li>权限申请审批与变更留痕</li></ul><blockquote><p>权限模型的完整说明见 <a href="./permissions">权限模型</a>。</p></blockquote><h2 id="多租户" tabindex="-1">多租户 <a class="header-anchor" href="#多租户" aria-label="Permalink to &quot;多租户&quot;">​</a></h2><ul><li>字段级隔离，全局数据使用 <code>TenantId=0</code> 约定</li><li>邮箱全局唯一登录，登录后按归属自动落点（控制台 / 工作台 / 租户选择），可随时切换租户</li><li>超级管理员平台态运维，可切入任意租户代为管理</li><li>租户版本（Edition）权限白名单运行时门控；开通一站式建管理员、角色与授权；降级自动回收越权授权</li></ul><h2 id="审计日志" tabindex="-1">审计日志 <a class="header-anchor" href="#审计日志" aria-label="Permalink to &quot;审计日志&quot;">​</a></h2><ul><li><strong>访问 / API / 操作 / 异常 / 登录 / 实体变更（Diff）/ 权限变更</strong> 七类日志，各自独立写入</li><li>落库前自动脱敏（密码、令牌、密钥、证件号等）；实体变更区分新增 / 修改 / 删除 / 恢复</li><li><strong>链路时间线</strong>：按维度（如租户 / 用户 / 请求）横向拉通上述七类日志，按时间轴串联同一次操作的完整轨迹</li></ul><h2 id="代码生成" tabindex="-1">代码生成 <a class="header-anchor" href="#代码生成" aria-label="Permalink to &quot;代码生成&quot;">​</a></h2><ul><li>单表 / 树形 / 主从三种模式，从实体、DTO、API 到前端页面一键生成</li><li>基于 Scriban 模板，支持自定义；Zip 下载或直接写入文件</li></ul><h2 id="ai-能力" tabindex="-1">AI 能力 <a class="header-anchor" href="#ai-能力" aria-label="Permalink to &quot;AI 能力&quot;">​</a></h2><ul><li><strong>AI Provider 管理</strong>：多供应商注册（密钥加密落库、读侧不回显）、测试连接、设为默认</li><li><strong>提示词库</strong>：集中维护 AI 提示词模板，支持状态启停</li><li><strong>知识库（RAG）</strong>：文档摄取（切片 + 向量嵌入入库）、重建索引、检索问答（返回带引用来源的答案），并以技能形式接入 Agent 调用链</li></ul><h2 id="平台能力" tabindex="-1">平台能力 <a class="header-anchor" href="#平台能力" aria-label="Permalink to &quot;平台能力&quot;">​</a></h2><ul><li><strong>动态 API</strong>：应用服务经 <code>[DynamicApi]</code> 暴露，无 Controller 样板，Scalar 文档自动生成</li><li><strong>菜单单一事实源</strong>：后端 <code>PageRegistry</code> 统一注册菜单、路由、组件路径、权限码与国际化键</li><li><strong>全链路分布式缓存</strong>（授权快照、版本门控、菜单、配置、字典），写路径精准失效</li><li><strong>网关灰度发布</strong>（百分比 / 白名单 / 租户 / 请求头）、请求追踪、限流熔断</li><li><strong>OAuth2 / OIDC 授权服务器</strong>：平台本身可作为 SSO 提供方供第三方应用接入（客户端注册、授权码 / 令牌签发与吊销），与登录页消费的外部 OAuth2（GitHub 等）是相反方向的两套能力</li><li><strong>开放 API 个人凭证</strong>：用户自助申请 AppKey / AppSecret，用于服务端签名调用开放接口，可随时滚动密钥</li><li><strong>消息模板</strong>（邮件 / 短信 / 站内通知 / 机器人，Scriban 渲染，租户可覆盖默认）、SignalR 实时通知与在线聊天（单聊 / 群聊 / 部门会话，管理员可审计会话内容）</li><li><strong>机器人通知</strong>：钉钉 / 飞书 / 企业微信 Webhook 机器人配置，以及多实例 Telegram Bot 管理</li><li><strong>数据字典</strong>：键值对枚举集中维护，供表单、搜索下拉复用</li><li><strong>服务器监控</strong>：CPU / 内存 / 磁盘 / GPU / 网络 / 主板 / 运行时信息可视化</li><li><strong>文件多存储</strong>（本地 / S3 / OSS / COS / MinIO）、定时任务、审核工作流、国际化（中 / 英）</li></ul><h2 id="前端体验" tabindex="-1">前端体验 <a class="header-anchor" href="#前端体验" aria-label="Permalink to &quot;前端体验&quot;">​</a></h2><ul><li><strong>Schema 驱动列表页</strong>：搜索 / 表格 / 导出由配置生成，内置列设置、密度切换、高级搜索、个人视图保存、行悬停速览、树形模式与列宽拖拽</li><li><strong>权限 / 租户 / 偏好感知</strong>：页面、字段、操作三级按权限码过滤，字段级脱敏；列设置与搜索偏好同步到后端，多端一致</li><li>灵动岛全局反馈、多标签页、收藏夹、命令面板式全局搜索</li><li><strong>消息中心</strong>：顶部横幅、登录弹窗、通知中心，支持强制阅读与按角色 / 部门定向</li><li><strong>偏好中心</strong>：亮 / 暗主题、主题色、布局风格与紧凑度，偏好云端同步</li><li>富文本（Tiptap）与 Markdown 编辑器、Cron 可视化、JSON 编辑 / 查看</li><li>锁屏、水印、时区切换、导入 / 导出中心（模板导入、异步导出任务）</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./permissions">权限模型</a>：RBAC + ABAC 深入</li><li><a href="./architecture">系统架构</a>：模块划分与数据流</li><li><a href="./getting-started">快速开始</a>：本地跑起来</li></ul>',21)])])}const b=i(r,[["render",t]]);export{g as __pageData,b as default};
